import psycopg2

class UserProfiles:
    def __init__(self, db_config):
        self.conn = psycopg2.connect(**db_config)
        self.cursor = self.conn.cursor()

    def get_user(self, username=None, email=None, role=None, status=None):
        query = """
            SELECT *
            FROM users
            WHERE 1=1
        """

        conditions = []
        params = {}

        if username:
            conditions.append("username ILIKE %s")
            params['%s'] = f'%{username}%'

        if email:
            conditions.append("email ILIKE %s")
            params['%s'] = f'%{email}%'

        if role:
            conditions.append("role = %s")
            params['%s'] = role

        if status:
            conditions.append("status = %s")
            params['%s'] = status

        if conditions:
            query += ' AND '.join(conditions)
            self.cursor.execute(query, list(params.values()))

        return self.cursor.fetchall()

